import os
import json
import time
import hashlib
from datetime import datetime, timedelta
from flask import Flask, request, jsonify
from typing import Dict, Any, Optional

app = Flask(__name__)

class DiskCache:
    def __init__(self, cache_dir: str = "cache", default_ttl: int = 3600):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        os.makedirs(cache_dir, exist_ok=True)
    
    def _get_cache_key(self, url: str, params: Dict[str, Any]) -> str:
        key_string = f"{url}_{json.dumps(params, sort_keys=True)}"
        return hashlib.md5(key_string.encode()).hexdigest()
    
    def _is_expired(self, timestamp: float, ttl: int) -> bool:
        return time.time() > timestamp + ttl
    
    def get(self, url: str, params: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        cache_key = self._get_cache_key(url, params)
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        if not os.path.exists(cache_file):
            return None
        
        try:
            with open(cache_file, 'r') as f:
                data = json.load(f)
            
            if self._is_expired(data['timestamp'], data['ttl']):
                os.remove(cache_file)
                return None
            
            return data['data']
        except (json.JSONDecodeError, KeyError):
            return None
    
    def set(self, url: str, params: Dict[str, Any], data: Any, ttl: Optional[int] = None) -> None:
        cache_key = self._get_cache_key(url, params)
        cache_file = os.path.join(self.cache_dir, f"{cache_key}.json")
        
        ttl = ttl or self.default_ttl
        
        cache_data = {
            'data': data,
            'timestamp': time.time(),
            'ttl': ttl
        }
        
        with open(cache_file, 'w') as f:
            json.dump(cache_data, f)

# Initialize cache
cache = DiskCache()

